SELECT DISTINCT merchant_id
FROM merchants
WHERE lead_behaviour_profile_id = 1;

SELECT m.seller_id, mt.merchant_type
FROM merchants m
JOIN merchant_types mt ON m.merchant_type_id = mt.merchant_type_id;

SELECT seller_id, product_catalog_size
FROM merchants
WHERE product_catalog_size > (
    SELECT AVG(product_catalog_size)
    FROM merchants
);

SELECT sdr_name || ' (Email: ' || email || ')' AS SDR_Details
FROM sdrs
WHERE email LIKE '%@example.com';
